ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?department_head WHERE {
  ?m a :Management .
  ?p a :Position .
  ?m p:hasPositions ?p .
  ?e a :Employees .
  ?e p:hasPositions ?p .
  ?m p:Department_Head ?department_head .
  ?e p:name ?fullname_f .
  FILTER(STR(?fullname_f) = "Linda Green")
} }
  component_2: { SELECT ?team_leader WHERE {
  ?m a :Management .
  ?p a :Position .
  ?m p:hasPositions ?p .
  ?e a :Employees .
  ?e p:hasPositions ?p .
  ?m p:Team_Leader ?team_leader .
  ?e p:name ?fullname_f .
  FILTER(STR(?fullname_f) = "Linda Green")
} }
  full: { SELECT ?department_head ?team_leader WHERE {
  ?m a :Management .
  ?p a :Position .
  ?m p:hasPositions ?p .
  ?e a :Employees .
  ?e p:hasPositions ?p .
  ?m p:Department_Head ?department_head .
  ?m p:Team_Leader ?team_leader .
  ?e p:name ?fullname_f .
  FILTER(STR(?fullname_f) = "Linda Green")
} }
}
